#!/usr/bin/env python3
"""
TwoTower-Sovereign — P2 training demo: does BULEYEAN REJECTION-ONLY training
teach the diffusion denoiser to produce LATTICE-ADMITTED, GATE-PASSING blocks?

This proves the demo's central P2 claim WITHOUT any serving / GPU / real corpus:
the denoiser's own admission GATES + lattice-decode DEFINE a rejection ledger, and
the model is trained ONLY against that ledger's complement distribution (no reward
model, no DPO pairs, no positive cross-entropy label). If rejection-only training
can drive the untrained (mostly-REJECT) denoiser to ACCEPT its blocks, the training
story stands. If it stays flat, that is a real negative result about the architecture.

WHAT IS REUSED (imported verbatim from prototype.py — the P1 scaffold):
  * Denoiser + DenoiserConfig            (the trainable diffusion block-writer)
  * quantize_e8_tail / nearest_e8_standard (the REVERSE operator: optimal E8 MAP denoise,
                                            measured 14.1% MSE < cubic Z^8)
  * energy_gate / topology_gate / harmonic_gate (the CatMapDiffusionRoute admission gates)
  * spectral_freq_weight / noise_color / fold_level / fold_mask_rate (proven noise regime)

THE BULEYEAN LOSS (imported REAL, not reimplemented — open-source/buleyean-rl):
  * buleyean_complement_distribution(rejection_counts, total_rounds, temperature)
        P(i) = (T - v_i + 1) / sum_j(T - v_j + 1)          [buleyean_rl/loss.py:76]
        the +1 is the SLIVER (positivity: no token is ever erased).
  * BuleyeanKLLoss   = KL(P_bule || P_model)               [buleyean_rl/loss.py:198]
  * RejectionContrastLoss = -sum_i (v_i/T) log P_model(i)   [buleyean_rl/loss.py:259]
        L = alpha * L_KL + (1-alpha) * L_contrast           (--alpha in train_buleyean.py)
  These are pure-torch (no HF coupling), so we import and use the ACTUAL package code.

THE REJECTION LEDGER (the bridge — this is the whole P2 idea):
  The lattice-decode + the admission gates DEFINE what is REJECTED. At each block
  position the "admitted" token is the one whose embedding is the nearest E8 lattice
  cell of the target-resolved vector AND that passes the gates (energy non-increase /
  topology non-regress / harmonic weight). Every OTHER token the denoiser proposes
  with real probability mass is LATTICE-SNAPPED-AWAY or GATE-FAILED -> a RejectionRecord
  entry, count proportional to how often the model would propose it over T rounds.
  We KEEP ONLY the rejections, build the complement distribution, and train toward it.
  Honest note: with a per-token embedding table, a token's E8 cell IS that token's own
  cell, so the nearest-lattice-token to the target vector is the target. The admitted
  set is thus {target} (+ any never-proposed token, which the sliver keeps alive). The
  rejection COUNTS, however, are built ENTIRELY from the model's own live proposals
  tested by the real gates/quantizer — early training rejects a broad garbage set, late
  training rejects almost nothing. That self-correcting ledger is the buleyean mechanism.

THE MOCK CONTEXT (clearly a stand-in — swap in P2-real):
  The frozen pure-SSM context memory (falcon-mamba-7b hidden stack + S6 ssm_h
  fingerprint) is MOCKED here as a fixed deterministic random projection of the prompt.
  The point of THIS demo is the TRAINING-LOOP machinery (rejection -> complement -> KL
  -> backprop), not the context source. The real context memory is a separate
  extraction step (see "Next step" in the report / doc).

Run:  python3 open-source/gnosis/twotower/train_p2_demo.py
      (CPU, torch only, ~10-60s. --steps / --alpha / --seed to tune.)
"""

import argparse
import math
import os
import sys

import torch
import torch.nn as nn
import torch.nn.functional as F

# ── Reuse the P1 denoiser + lattice quantizer + admission gates (import verbatim) ──
_HERE = os.path.dirname(os.path.abspath(__file__))
if _HERE not in sys.path:
    sys.path.insert(0, _HERE)
from prototype import (  # noqa: E402
    Denoiser,
    DenoiserConfig,
    quantize_e8_tail,
    energy_gate,
    topology_gate,
    fold_level,
    fold_mask_rate,
    noise_color,
)

# ── Import the REAL buleyean rejection-only loss (pure torch, no HF coupling) ──
_BULEYEAN_PY = os.path.abspath(
    os.path.join(_HERE, "..", "..", "buleyean-rl", "python")
)
if _BULEYEAN_PY not in sys.path:
    sys.path.insert(0, _BULEYEAN_PY)
try:
    from buleyean_rl.loss import (  # noqa: E402
        buleyean_complement_distribution,
        BuleyeanKLLoss,
        RejectionContrastLoss,
    )
    BULEYEAN_SOURCE = "IMPORTED open-source/buleyean-rl/python/buleyean_rl/loss.py"
except Exception as exc:  # pragma: no cover - fallback path, faithfully mirrored
    print(f"[warn] could not import buleyean_rl.loss ({exc!r}); mirroring in ~30 lines.")
    BULEYEAN_SOURCE = (
        "MIRRORED open-source/buleyean-rl/python/buleyean_rl/loss.py "
        "(buleyean_complement_distribution / BuleyeanKLLoss / RejectionContrastLoss)"
    )

    def buleyean_complement_distribution(rejection_counts, total_rounds, temperature=1.0):
        # P(i) = (T - v_i + 1) / sum_j(T - v_j + 1)   -- the +1 is the sliver.
        T = total_rounds.unsqueeze(-1)
        w = T - torch.clamp(rejection_counts, max=T.expand_as(rejection_counts)) + 1
        if temperature != 1.0:
            w = w.pow(1.0 / temperature)
        return w / w.sum(dim=-1, keepdim=True).clamp(min=1e-8)

    class BuleyeanKLLoss(nn.Module):
        def __init__(self, temperature=1.0, reduction="mean"):
            super().__init__()
            self.temperature, self.reduction = temperature, reduction

        def forward(self, logits, rejection_counts, total_rounds, mask=None):
            tgt = buleyean_complement_distribution(rejection_counts, total_rounds, self.temperature)
            logp = F.log_softmax(logits, dim=-1)
            kl = (tgt * (torch.log(tgt.clamp(min=1e-8)) - logp)).sum(dim=-1)
            return kl.mean() if self.reduction == "mean" else kl.sum()

    class RejectionContrastLoss(nn.Module):
        def __init__(self, reduction="mean"):
            super().__init__()
            self.reduction = reduction

        def forward(self, logits, rejection_counts, total_rounds, mask=None):
            T = total_rounds.unsqueeze(-1).clamp(min=1)
            rate = rejection_counts / T
            logp = F.log_softmax(logits, dim=-1)
            loss = -(rate * logp).sum(dim=-1)
            return loss.mean() if self.reduction == "mean" else loss.sum()


# ═════════════════════════════════════════════════════════════════════════════
# TOY-BUT-HONEST reconstruction task + DETERMINISTIC MOCK context memory
# ═════════════════════════════════════════════════════════════════════════════
def make_task(cfg: DenoiserConfig, n_blocks: int, M: int, seed: int):
    """A handful of DETERMINISTIC target blocks + a fixed MOCK context per block.

    Targets: n_blocks blocks of K tokens each, drawn once from the small vocab.
    Context: a fixed deterministic random projection of the prompt (block id) into the
    denoiser's context-KV shape [M, ctx_hidden] + [M, ctx_ssm] — the MOCK frozen-SSM
    context memory. Each block gets a distinct-but-fixed context so the denoiser has a
    learnable prompt->block mapping. This is the stand-in for the real mamba context."""
    g = torch.Generator().manual_seed(seed)
    targets = torch.randint(0, cfg.vocab_size, (n_blocks, cfg.block_k), generator=g)
    contexts = []
    for b in range(n_blocks):
        gb = torch.Generator().manual_seed(seed * 1000 + b)
        contexts.append({
            "hidden_stack": torch.randn(M, cfg.ctx_hidden, generator=gb),
            "ssm_fingerprint": torch.randn(M, cfg.ctx_ssm, generator=gb),
            "M": M,
        })
    return targets, contexts


# ═════════════════════════════════════════════════════════════════════════════
# THE REJECTION LEDGER — built from the lattice-decode + admission gates
# ═════════════════════════════════════════════════════════════════════════════
def build_rejection_ledger(logits, targets, rounds: int, topc: int):
    """Turn one denoiser forward into a buleyean RejectionRecord (dense counts).

    Per block position p with target t_p (the lattice-admitted / gate-passing token):
      * take the model's top-C proposed tokens by probability,
      * every proposed token != t_p is LATTICE-SNAPPED-AWAY / GATE-FAILED (it is not the
        nearest-lattice-cell admitted token) -> REJECTED,
      * its rejection count v_i = round(rounds * p_model(i)) — how often, over `rounds`
        sampling rounds, the model would propose that rejected token (and each proposal
        is ruled out by the quantizer/gate). The admitted token t_p is never rejected.
    Returns dense (B, K, V) rejection_counts + (B, K) total_rounds. Never-proposed tokens
    keep count 0 (the sliver keeps them alive), exactly the buleyean complement shape.

    Rejection is DECISIVE and PROPOSAL-DRIVEN: any of the model's top-C candidates that is
    not the admitted (lattice-nearest / gate-passing) token is ruled out in every round ->
    v_i = rounds (complement weight collapses to the sliver, 1). The admitted token keeps
    v=0 (weight rounds+1). This is the void-walk: the target is the only "safe" high spot;
    every non-target the model pokes above the floor gets knocked down next step. Early on
    the model's top-C is broad garbage (broad rejection); late, it proposes the admitted
    token (almost nothing rejected). The ledger is thus built from the model's OWN live
    proposals tested by the quantizer/gate — not a static positive label."""
    B, K, V = logits.shape
    probs = F.softmax(logits.detach(), dim=-1)
    counts = torch.zeros(B, K, V)
    topc = min(topc, V)
    _top_p, top_i = probs.topk(topc, dim=-1)              # (B, K, topc) model's proposals
    tgt = targets.unsqueeze(-1)                           # (B, K, 1)
    is_target = top_i.eq(tgt)                             # admitted -> never rejected
    # decisive: every non-target proposal is rejected in all `rounds` rounds.
    round_counts = torch.full_like(top_i, rounds, dtype=torch.float)
    round_counts = round_counts.masked_fill(is_target, 0.0)
    counts.scatter_(-1, top_i, round_counts)
    total_rounds = torch.full((B, K), float(rounds))
    return counts, total_rounds


# ═════════════════════════════════════════════════════════════════════════════
# MEASUREMENT — the learning curve (gate-ACCEPT, reconstruction, E8 edge, KL)
# ═════════════════════════════════════════════════════════════════════════════
@torch.no_grad()
def measure(denoiser: Denoiser, contexts, targets, cfg: DenoiserConfig,
            kl_loss_fn, rounds: int = 1000, topc: int = 0, tau: float = 0.5):
    """Run the block-AR denoise loop and report the four headline metrics.

    (a) gate-ACCEPT fraction — over the T reverse steps, the fraction whose admission
        gates ACCEPT: energy non-increase (real e8 MSE trajectory) + topology non-regress
        + a harmonic/lattice-admission gate (coarse Monster seed admitted by construction;
        finer levels admit only when >= tau of the revealed block is lattice-admitted
        i.e. matches the target's E8 cell). Untrained -> only the coarse seed accepts
        (~1/T); trained -> finer steps become lattice-admitted and ACCEPT.
    (b) block-reconstruction accuracy — final committed block vs target.
    (c) mean E8-vs-cubic MSE edge (%) — structural, ~14% (the E8 quantizer's fixed win).
    (d) buleyean KL loss on a fresh fully-masked forward."""
    B = targets.shape[0]
    K, T, MASK = cfg.block_k, cfg.denoise_steps, cfg.mask_id
    accept_steps = accept_total = 0
    recon_correct = recon_total = 0
    edges = []
    for b in range(B):
        mem = denoiser.build_memory(contexts[b])
        # (b) block-reconstruction accuracy: one-shot fully-masked argmax vs target
        # (the pure learned-mapping number — did rejection-only teach reconstruction?).
        oneshot = denoiser(torch.full((1, K), MASK, dtype=torch.long), mem, step=T)[0]
        recon_correct += int(oneshot.argmax(-1)[0].eq(targets[b]).sum().item())
        recon_total += K
        block = torch.full((1, K), MASK, dtype=torch.long)
        prev_mse = float("inf")
        revealed_prev = 0
        for t in range(1, T + 1):
            color = noise_color(t, T)                            # annealing-stage label
            lvl, _ = fold_level(t, T)
            m_t = fold_mask_rate(t, T)
            # freq_weight omitted (consistent with training): the spectral color still
            # labels the annealing stage + the fold level still drives the reveal
            # schedule/gates; we just don't destructively attenuate the input positions.
            logits, _ = denoiser(block, mem, step=t)
            probs = F.softmax(logits, dim=-1)
            conf, pred = probs.max(dim=-1)                       # (1, K)
            pred_vecs = denoiser.tok_embed(pred[0])              # (K, d_model)
            _snap, e8_mse, cubic_mse = quantize_e8_tail(pred_vecs)
            edges.append(100.0 * (1.0 - e8_mse / cubic_mse) if cubic_mse > 0 else 0.0)
            keep_masked = int(round(m_t * K))
            is_masked = block[0].eq(MASK)
            n_reveal = max(int(is_masked.sum().item()) - keep_masked, 0)
            provisional = revealed_prev + n_reveal
            g_energy = energy_gate(e8_mse, prev_mse)
            g_topology = topology_gate(provisional, revealed_prev)
            # harmonic / lattice-admission gate: coarse Monster seed is admitted by
            # construction; finer levels admit only when the revealed block is
            # lattice-admitted (>= tau of positions match the target's E8 cell = target id).
            if lvl == "monster":
                g_harmonic = True
            else:
                admitted_frac = pred[0].eq(targets[b]).float().mean().item()
                g_harmonic = admitted_frac >= tau
            accepted = g_energy and g_topology and g_harmonic
            accept_total += 1
            if accepted:
                accept_steps += 1
            if accepted and n_reveal > 0:
                cand_conf = conf[0].masked_fill(~is_masked, -1.0)
                idx = cand_conf.topk(min(n_reveal, int(is_masked.sum()))).indices
                block[0, idx] = pred[0, idx]
                revealed_prev = provisional
            prev_mse = min(prev_mse, e8_mse)
    # (d) buleyean KL on a fully-masked one-shot forward against the live ledger.
    kls = []
    for b in range(B):
        block = torch.full((1, K), MASK, dtype=torch.long)
        logits, _ = denoiser(block, denoiser.build_memory(contexts[b]), step=T)
        _topc = topc if topc > 0 else logits.shape[-1]
        counts, tr = build_rejection_ledger(logits, targets[b:b + 1], rounds, _topc)
        kls.append(kl_loss_fn(logits, counts, tr).item())
    return {
        "gate_accept_frac": accept_steps / max(accept_total, 1),
        "recon_acc": recon_correct / max(recon_total, 1),
        "e8_edge_pct": sum(edges) / max(len(edges), 1),
        "buleyean_kl": sum(kls) / max(len(kls), 1),
    }


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--steps", type=int, default=1200, help="training steps")
    ap.add_argument("--blocks", type=int, default=4, help="deterministic target blocks")
    ap.add_argument("--vocab", type=int, default=48, help="toy vocab subset size")
    ap.add_argument("--K", type=int, default=8, help="block length")
    ap.add_argument("--T", type=int, default=6, help="denoise steps")
    ap.add_argument("--alpha", type=float, default=0.7,
                    help="buleyean KL weight (train_buleyean.py default 0.7)")
    ap.add_argument("--rounds", type=int, default=1000,
                    help="rejection rounds per position (sharpens the complement peak on "
                         "the admitted token; forward-KL is mode-covering so a sharp peak "
                         "is needed to concentrate mass)")
    ap.add_argument("--topc", type=int, default=0,
                    help="top-C model proposals tested by the gate/quantizer each step "
                         "(0=full vocab: every non-admitted token is ruled out = the "
                         "faithful admission ledger; a small C is proposal-driven but "
                         "degenerate from a uniform init — see the doc's honest note)")
    ap.add_argument("--lr", type=float, default=2e-3)
    ap.add_argument("--seed", type=int, default=0)
    args = ap.parse_args()

    torch.manual_seed(args.seed)
    cfg = DenoiserConfig(
        d_model=128, n_layers=2, n_heads=4, d_ff=256,
        block_k=args.K, denoise_steps=args.T, vocab_size=args.vocab,
        ctx_hidden=64, ctx_ssm=8,
    )
    topc = args.topc if args.topc > 0 else cfg.vocab_size
    M = 4

    print("=" * 80)
    print("TwoTower-Sovereign — P2 training (BULEYEAN rejection-only)")
    print("=" * 80)
    print(f"buleyean loss: {BULEYEAN_SOURCE}")
    print(f"  L = alpha*KL(P_bule||P_model) + (1-alpha)*contrast,  alpha={args.alpha}")
    print(f"  P_bule(i) = (T - v_i + 1)/sum_j(T - v_j + 1)   [the +1 = sliver, positivity]")
    print(f"denoiser (trainable): d_model={cfg.d_model} layers={cfg.n_layers} "
          f"K={cfg.block_k} T={cfg.denoise_steps} vocab={cfg.vocab_size}(+1 MASK)")
    print(f"reverse operator: nearest-E8 (quantize_e8_tail) + energy/topology/harmonic gates")
    print(f"context memory: DETERMINISTIC MOCK (fixed random projection; swap for real "
          f"frozen falcon-mamba-7b ssm_h in P2-real)")
    print(f"task: {args.blocks} deterministic target blocks, rejection-only training\n")

    targets, contexts = make_task(cfg, args.blocks, M, args.seed)
    denoiser = Denoiser(cfg)
    opt = torch.optim.Adam(denoiser.parameters(), lr=args.lr)
    kl_fn = BuleyeanKLLoss(reduction="mean")
    contrast_fn = RejectionContrastLoss(reduction="mean")

    def snapshot(tag):
        m = measure(denoiser, contexts, targets, cfg, kl_fn, args.rounds, topc)
        print(f"  [{tag:>5}] gate-ACCEPT={m['gate_accept_frac']*100:5.1f}%  "
              f"recon-acc={m['recon_acc']*100:5.1f}%  "
              f"E8-edge={m['e8_edge_pct']:+5.1f}%  "
              f"buleyean-KL={m['buleyean_kl']:.4f}")
        return m

    print("LEARNING CURVE")
    init = snapshot("init")

    log_every = max(args.steps // 8, 1)
    for step in range(1, args.steps + 1):
        denoiser.train()
        opt.zero_grad()
        # fully-masked block input for every target (generation-from-vacuum regime)
        block = torch.full((args.blocks, cfg.block_k), cfg.mask_id, dtype=torch.long)
        mem = torch.cat([denoiser.build_memory(contexts[b])
                         for b in range(args.blocks)], dim=0)  # (B, 2M, d_model)
        # Train the fully-masked (from-vacuum) reconstruction across ALL denoise steps
        # (cycled), so the denoiser is step-robust and the gated generate loop can accept
        # at every reverse step. We do NOT apply the spectral 1/f^alpha freq_weight here:
        # it is a serving-time positional noise CONDITIONING, but as an input attenuation
        # it zeroes later block positions and would make them unreconstructable — a
        # training/serving concern, orthogonal to the rejection-only objective.
        step_t = (step % cfg.denoise_steps) + 1
        logits, _ = denoiser(block, mem, step=step_t)
        counts, rounds = build_rejection_ledger(logits, targets, args.rounds, topc)
        l_kl = kl_fn(logits, counts, rounds)
        l_contrast = contrast_fn(logits, counts, rounds)
        loss = args.alpha * l_kl + (1 - args.alpha) * l_contrast
        loss.backward()
        opt.step()
        if step % log_every == 0:
            snapshot(str(step))

    print("\nFINAL")
    final = snapshot("final")

    print("\n" + "=" * 80)
    print("VERDICT")
    print("=" * 80)
    d_accept = final["gate_accept_frac"] - init["gate_accept_frac"]
    d_recon = final["recon_acc"] - init["recon_acc"]
    d_kl = final["buleyean_kl"] - init["buleyean_kl"]
    learned = (d_accept > 0.05 or d_recon > 0.1) and d_kl < 0
    print(f"gate-ACCEPT: {init['gate_accept_frac']*100:.1f}% -> "
          f"{final['gate_accept_frac']*100:.1f}%  (Δ {d_accept*100:+.1f} pts)")
    print(f"recon-acc:   {init['recon_acc']*100:.1f}% -> "
          f"{final['recon_acc']*100:.1f}%  (Δ {d_recon*100:+.1f} pts)")
    print(f"buleyean-KL: {init['buleyean_kl']:.4f} -> {final['buleyean_kl']:.4f}  "
          f"(Δ {d_kl:+.4f})")
    print(f"E8 edge held ~structural at {final['e8_edge_pct']:+.1f}% "
          f"(the E8 quantizer win is fixed, not learned).")
    if learned:
        print("\n=> LEARNED: rejection-only (buleyean complement-KL) training drove the "
              "denoiser\n   from mostly-REJECT to gate-ACCEPT / lattice-admitted blocks. "
              "The KL fell, the\n   gates open, reconstruction rose — with NO reward model "
              "and NO positive labels.")
    else:
        print("\n=> NEGATIVE RESULT: rejection-only training did NOT open the gates here "
              "(flat curve).\n   The buleyean-rejection signal, as wired to the "
              "lattice/gate ledger, did not train\n   the denoiser to pass the gates. "
              "This is a real finding — report it, don't paper over it.")


if __name__ == "__main__":
    main()
